CREATE TABLE roles (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(80) NOT NULL UNIQUE,description VARCHAR(255));
CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,email VARCHAR(160) NOT NULL UNIQUE,password_hash VARCHAR(255) NOT NULL,role_id INT NOT NULL,status ENUM('active','inactive') NOT NULL DEFAULT 'active',created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,FOREIGN KEY(role_id) REFERENCES roles(id));
CREATE TABLE clients (id INT AUTO_INCREMENT PRIMARY KEY,company_name VARCHAR(180) NOT NULL,company_rut VARCHAR(30) NOT NULL,contact_name VARCHAR(140) NOT NULL,position VARCHAR(120),email VARCHAR(160) NOT NULL,phone VARCHAR(60),workers_count INT DEFAULT 0,industry VARCHAR(120),city VARCHAR(120),risk_score DECIMAL(5,2),risk_level VARCHAR(40),risk_status VARCHAR(40) DEFAULT 'Nuevo',recommended_action TEXT,source VARCHAR(80),notes TEXT,assigned_user_id INT NULL,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,INDEX idx_clients_search(company_name,company_rut,email),INDEX idx_clients_risk(risk_level),FOREIGN KEY(assigned_user_id) REFERENCES users(id) ON DELETE SET NULL);
CREATE TABLE assessment_questions (id INT AUTO_INCREMENT PRIMARY KEY,module_name VARCHAR(120) NOT NULL,question_text TEXT NOT NULL,weight DECIMAL(5,2) NOT NULL,sort_order INT NOT NULL,status TINYINT(1) NOT NULL DEFAULT 1);
CREATE TABLE assessment_answers (id INT AUTO_INCREMENT PRIMARY KEY,client_id INT NOT NULL,question_id INT NOT NULL,answer_value TINYINT NOT NULL,answer_label VARCHAR(30) NOT NULL,module_name VARCHAR(120) NOT NULL,created_at TIMESTAMP NULL,FOREIGN KEY(client_id) REFERENCES clients(id) ON DELETE CASCADE,FOREIGN KEY(question_id) REFERENCES assessment_questions(id));
CREATE TABLE assessment_results (id INT AUTO_INCREMENT PRIMARY KEY,client_id INT NOT NULL,labor_score DECIMAL(5,2),pension_score DECIMAL(5,2),safety_score DECIMAL(5,2),document_score DECIMAL(5,2),contractor_score DECIMAL(5,2),final_score DECIMAL(5,2),risk_level VARCHAR(40),recommendation TEXT,created_at TIMESTAMP NULL,FOREIGN KEY(client_id) REFERENCES clients(id) ON DELETE CASCADE);
CREATE TABLE activity_logs (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,action VARCHAR(80) NOT NULL,entity_type VARCHAR(80),entity_id INT,description TEXT,ip_address VARCHAR(60),created_at TIMESTAMP NULL,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL);
CREATE TABLE settings (id INT AUTO_INCREMENT PRIMARY KEY,setting_key VARCHAR(120) NOT NULL UNIQUE,setting_value TEXT);
